@Override
public Page<PointDTO> getAutomaticPendingPoints(Pageable pageable) {
    // Récupération de la date actuelle (mois et année)
    YearMonth currentYearMonth = YearMonth.now();
    LocalDateTime startOfMonth = currentYearMonth.atDay(1).atStartOfDay();
    LocalDateTime endOfMonth = currentYearMonth.atEndOfMonth().atTime(23, 59, 59);
    // Étape 1: Récupérer tous les IDs d'utilisateurs
    List<String> userIds = getUserIdsFromUserService();
    // Étape 2: Pour chaque utilisateur, vérifier s'il a un point AUTOMATIC & PENDING ce mois-ci
    for (String userId : userIds) {
        boolean hasPoint = pointRepository.existsByUserIdAndAssignmentModeAndValidationStatusAndAssignmentDateBetween(userId, EAssignmentMode.AUTOMATIC, EPointValidationStatus.PENDING, startOfMonth, endOfMonth);
        // Étape 3: Si pas d'enregistrement, en créer un
        if (!hasPoint) {
            Point point = Point.builder().assignmentDate(LocalDateTime.now()).assignmentMode(EAssignmentMode.AUTOMATIC).criterion("Points initialement cumulés").pointCount(1200.0).validationStatus(EPointValidationStatus.PENDING).userId(userId).build();
            pointRepository.save(point);
        }
    }
    // Étape 4: Retourner les points AUTOMATIC et PENDING comme avant
    return pointRepository.findByAssignmentModeAndValidationStatus(EAssignmentMode.AUTOMATIC, EPointValidationStatus.PENDING, pageable).map(point -> {
        PointDTO dto = PointMapper.toDto(point);
        UserResponse user = getUserFromUserService(point.getUserId());
        if (user != null) {
            dto.setFirstName(user.getFirstName());
            dto.setLastName(user.getLastName());
        }
        return dto;
    });
}

