    // Rectification des points affectés automatiquement
    @Override
    public void createManualPointFromAutomatic(String pointId, String criterion, Double pointCount) throws FunctionalException, TechnicalException {
        try {
            String userId = pointRepository.findUserIdByPointId(pointId).orElseThrow(() -> new FunctionalException("Point not found"));
            // Récupérer le dernier point de l'utilisateur pour le mois/année en cours
            LocalDateTime startOfMonth = LocalDateTime.now().withDayOfMonth(1).withHour(0).withMinute(0).withSecond(0).withNano(0);
            LocalDateTime endOfMonth = startOfMonth.plusMonths(1);
            Pageable pageable = PageRequest.of(0, 1, Sort.by(Sort.Direction.DESC, "assignmentDate"));
            List<Point> lastPoints = pointRepository.findByUserIdAndAssignmentDateBetween(userId, startOfMonth, endOfMonth, pageable).getContent();
            double previousPoints = lastPoints.isEmpty() ? 0.0 : lastPoints.get(0).getPointCount();
            // Étape 1: Enregistrement intermédiaire du point (log de rectification)
            Point intermediateLogPoint = Point.builder().assignmentDate(LocalDateTime.now()).assignmentMode(// ou un mode spécifique comme "RECTIFICATION"
            EAssignmentMode.MANUAL).criterion(criterion).pointCount(pointCount).validationStatus(EPointValidationStatus.APPROVED).userId(userId).build();
            pointRepository.save(intermediateLogPoint);
            // Étape 2: Enregistrement du point manuel avec la somme totale
            double totalPointCount = previousPoints + pointCount;
            Point manualPoint = Point.builder().assignmentDate(LocalDateTime.now()).assignmentMode(EAssignmentMode.MANUAL).criterion(criterion).pointCount(totalPointCount).validationStatus(EPointValidationStatus.APPROVED).userId(userId).build();
            pointRepository.save(manualPoint);
        } catch (FunctionalException e) {
            throw e;
        } catch (Exception e) {
            throw new TechnicalException(TechnicalExceptionType.SYSTEM_ERROR);
        }
    }

