@Override
public Page<RewardDTO> getAllRewards(Pageable pageable) {
    YearMonth currentMonth = YearMonth.now();
    YearMonth previousMonth = currentMonth.minusMonths(1);
    // Tous les utilisateurs
    List<String> userIds = pointService.getUserIds();
    for (String userId : userIds) {
        double previousMonthPoints = pointService.getTotalPointsForUserByMonth(userId, previousMonth.getYear(), previousMonth.getMonthValue());
        boolean alreadyRewardedThisMonth = rewardRepository.existsByUserIdAndTypeAndRewardDateBetween(userId, ERewardType.PRIME, currentMonth.atDay(1).atStartOfDay(), currentMonth.atEndOfMonth().atTime(23, 59, 59));
        if (previousMonthPoints > 2000 && !alreadyRewardedThisMonth) {
            // Construction du reward SANS JAMAIS inclure l'ID
            Reward reward = Reward.builder().type(ERewardType.PRIME).activationStatus(ERewardActivationStatus.DEACTIVATED).blockStatus(ERewardBlockStatus.BLOCKED).rewardDate(LocalDateTime.now()).userId(userId).description("Récompense automatique pour plus de 2000 points au mois précédent").build();
            rewardRepository.save(reward);
