@Override
public void updateRewardType(String rewardId, ERewardType newType) throws FunctionalException {
    Reward reward = rewardRepository.findByUuid(rewardId).orElseThrow(() -> new FunctionalException("Reward not found with id: " + rewardId));
    reward.setType(newType);
    rewardRepository.save(reward);
