            UserResponse user = getUserFromUserService(reward.getUserId());
            if (user == null || user.getEntryDate() == null) {
                throw new FunctionalException("User not found or entry date is missing for reward id: " + rewardId);
            }
            long monthsOfSeniority = ChronoUnit.MONTHS.between(user.getEntryDate().withDayOfMonth(1), LocalDateTime.now().withDayOfMonth(1));
            if (monthsOfSeniority < 3) {
                throw new FunctionalException("L'activation n'est autorisée que pour les employés avec au moins 3 mois d'ancienneté.");
            }
        }
        // Cas 2 : Passage de ACTIVATED à DEACTIVATED => Aucun contrôle nécessaire
        reward.setActivationStatus(newStatus);
        rewardRepository.save(reward);
    }

    @Override
    public UserWorkingHoursDTO getUserWorkingHours(String userId) {
        UserResponse user = getUserFromUserService(userId);
        if (user == null || user.getEntryDate() == null) {
            return new UserWorkingHoursDTO(userId, 0L);
        }
        LocalDateTime endDate = user.getExitDate() != null ? user.getExitDate() : LocalDateTime.now();
        long hours = java.time.Duration.between(user.getEntryDate(), endDate).toHours();
        return new UserWorkingHoursDTO(userId, hours);
    }

    @Override
    public WorkingMonthDTO getWorkingMonthsByUserId(String userId) {
        UserResponse user = getUserFromUserService(userId);
        if (user == null || user.getEntryDate() == null) {
            return new WorkingMonthDTO(userId, 0);
        }
        LocalDateTime startDate = user.getEntryDate();
        LocalDateTime endDate = user.getExitDate() != null ? user.getExitDate() : LocalDateTime.now();
        long monthsBetween = ChronoUnit.MONTHS.between(startDate.withDayOfMonth(1), endDate.withDayOfMonth(1));
        return new WorkingMonthDTO(userId, (int) monthsBetween);
    }
}

